import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styles: [`
    :host {
      --primary: #4f46e5;
      --primary-hover: #4338ca;
      --dark: #111827;
      --text-main: #374151;
      --text-light: #6b7280;
      --bg-subtle: #f9fafb;
    }

    .auth-wrapper {
      min-height: 100vh;
      display: flex;
      align-items: center;
      justify-content: center;
      background-color: #f3f4f6;
      padding: 2rem;
      font-family: 'Inter', system-ui, -apple-system, sans-serif;
    }

    .auth-card {
      display: flex;
      width: 100%;
      max-width: 1000px;
      background: #ffffff;
      border-radius: 24px;
      overflow: hidden;
      box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.1);
    }

    .auth-aside {
      flex: 1;
      background: linear-gradient(135deg, #1e1b4b 0%, #312e81 100%);
      padding: 3rem;
      color: white;
      display: flex;
      flex-direction: column;
      justify-content: space-between;
    }

    .auth-main {
      flex: 1.2;
      padding: 4rem;
      display: flex;
      align-items: center;
    }

    .modern-input {
      width: 100%;
      padding: 0.75rem 1rem;
      border: 1.5px solid #e5e7eb;
      border-radius: 10px;
      font-size: 1rem;
    }

    .btn-submit {
      width: 100%;
      margin-top: 2.5rem;
      background: var(--primary);
      color: white;
      border: none;
      padding: 1rem;
      border-radius: 10px;
      font-weight: 700;
      cursor: pointer;
    }

    /* ✅ TOAST */

    .toast {
      position: fixed;
      top: 20px;
      right: 20px;
      background: #22c55e;
      color: white;
      padding: 12px 18px;
      border-radius: 8px;
      font-weight: 500;
      z-index: 9999;
    }

    .toast-error {
      background: #ef4444;
    }

  `]
})
export class LoginComponent {

  role = 'CANDIDATE';
  email = '';
  name = '';
  password = '';
  emailExists = true;

  // ✅ NEW
  showToast = false;
  toastMessage = '';
  isError = false;

  interviewers = {
    Kavya: { id: 1, password: 'kavya123' },
    Arun: { id: 2, password: 'arun123' },
    Divya: { id: 3, password: 'divya123' }
  };

  constructor(private auth: AuthService, private router: Router) {}

  ngOnInit() {
    this.email = '';
    this.password = '';
    this.name = '';
  }

  setRole(r: string) {
    this.role = r;
  }

  showError(msg: string) {
    this.toastMessage = msg;
    this.isError = true;
    this.showToast = true;

    setTimeout(() => {
      this.showToast = false;
    }, 2500);
  }

  handleLogin() {

    if (this.role === 'CANDIDATE') {

      if (!this.email) {
        this.showError("Enter email");
        return;
      }

      if (!this.emailExists) {
        this.showError("Email not registered");
        return;
      }

      if (!this.password) {
        this.showError("Enter password");
        return;
      }

      const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

      if (!emailPattern.test(this.email)) {
        this.showError("Invalid email");
        return;
      }

      this.auth.loginCandidate(this.email, this.password).subscribe({

        next: () => {

          this.auth.login('CANDIDATE', { email: this.email });
          this.router.navigate(['/candidate/dashboard']);

        },

        error: (err) => {

          if (err.error) {

            if (err.error.message) {
              this.showError(err.error.message);
              return;
            }

            if (typeof err.error === 'string') {
              this.showError(err.error);
              return;
            }

          }

          this.showError("Login failed");

        }

      });

    }

    // HR
    if (this.role === 'HR') {

      if (this.email !== 'admin@gmail.com' || this.password !== 'admin123') {
        this.showError("Invalid HR credentials");
        return;
      }

      this.auth.login('HR');
      this.router.navigate(['/hr/dashboard']);
    }

    // Interviewer
    if (this.role === 'INTERVIEWER') {

      const interviewer = (this.interviewers as any)[this.name];

      if (!interviewer || interviewer.password !== this.password) {
        this.showError("Invalid credentials");
        return;
      }

      this.auth.login('INTERVIEWER', {
        interviewerId: interviewer.id,
        interviewerName: this.name
      });

      this.router.navigate([`/interviewer/${interviewer.id}`]);
    }

  }

  checkEmail() {

    if (!this.email) return;

    this.auth.checkCandidateEmail(this.email).subscribe({
      next: (res: boolean) => {
        this.emailExists = res;
      }
    });

  }

  goToRegister(){
    this.router.navigate(['/register']);
  }

}
